UPDATE TW_EVAL
   SET EVAL_STATUS = #{evalStatus}
     , EVAL_RESULT = #{evalResult}
     , TOTAL_SCORE = #{totalScore}
     , UPD_DT = NOW()
     , UPD_USER = #{updUser}
 WHERE EVAL_ID = #{evalId}

mapper.select:
SELECT ed.* , t.NODE_NM , p.NODE_NM AS PARENT_NM FROM TW_EVAL_DTL ed LEFT JOIN TW_TREE t ON ed.NODE_ID = t.NODE_ID LEFT JOIN TW_TREE p ON t.PARENT_ID = p.NODE_ID WHERE ed.EVAL_ID = #{evalId}
AND ed.NODE_ID = #{nodeId}
ORDER BY t.SORT_ORD

mapper.update:
UPDATE TW_EVAL_DTL
   SET SCORE = #{score}
     , GRADE = #{grade}
     , EVIDENCE = #{evidence}
     , NOTE = #{note}
     , EVAL_USER = #{evalUser}
     , EVAL_DT = NOW()
 WHERE DTL_ID = #{dtlId}
